    "content": "version: '3.8'\n\nservices:\n  app:\n    build:\n      context: ..\n      dockerfile: docker/Dockerfile\n    ports:\n      - \"3000:3000\"\n      - \"3001:3001\"\n    environment:\n      - NODE_ENV=production\n      - DATABASE_URL=${DATABASE_URL}\n      - JWT_SECRET=${JWT_SECRET}\n      - FIREBASE_KEY=${FIREBASE_KEY}\n      - VITE_API_URL=http://localhost:3001\n    volumes:\n      - ./data:/app/data\n    networks:\n      - co-chat-network\n\n  mongo:\n    image: mongo:6\n    environment:\n      - MONGO_INITDB_DATABASE=cochat\n    volumes:\n      - mongo-data:/data/db\n    networks:\n      - co-chat-network\n    ports:\n      - \"27017:27017\"\n\nvolumes:\n  mongo-data:\n\nnetworks:\n  co-chat-network:\n"
