    "path": "client/src/pages/HomePage.tsx",
    "content": "import { useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\n\nexport default function HomePage() {\n  const [searchQuery, setSearchQuery] = useState('')\n  const [isDark, setIsDark] = useState(false)\n  const navigate = useNavigate()\n  const [chats] = useState([\n    { id: 1, name: 'Alice Johnson', lastMessage: 'Hey! How are you?', time: '2m ago', unread: 2 },\n    { id: 2, name: 'Team Dev', lastMessage: 'Meeting at 3 PM', time: '1h ago', unread: 0 },\n  ])\n\n  return (\n    <div className={`h-screen flex flex-col ${isDark ? 'bg-gray-900' : 'bg-white'}`}>\n      {/* Header */}\n      <div className={`${isDark ? 'bg-gray-800' : 'bg-blue-600'} text-white p-4 shadow-lg`}>\n        <div className=\"flex items-center justify-between mb-4\">\n          <h1 className=\"text-2xl font-bold\">💬 Co Chat</h1>\n          <div className=\"flex gap-2\">\n            <button\n              onClick={() => setIsDark(!isDark)}\n              className=\"p-2 rounded-full hover:bg-blue-700 transition\"\n            >\n              {isDark ? '☀️' : '🌙'}\n            </button>\n            <button\n              onClick={() => navigate('/profile')}\n              className=\"p-2 rounded-full hover:bg-blue-700 transition\"\n            >\n              👤\n            </button>\n          </div>\n        </div>\n\n        {/* Search Bar */}\n        <input\n          type=\"text\"\n          placeholder=\"Search chats, contacts...\"\n          value={searchQuery}\n          onChange={(e) => setSearchQuery(e.target.value)}\n          className=\"w-full px-4 py-2 rounded-full bg-blue-500 placeholder-blue-200 text-white focus:outline-none\"\n        />\n      </div>\n\n      {/* Chat List */}\n      <div className={`flex-1 overflow-y-auto ${isDark ? 'bg-gray-900' : 'bg-gray-50'}`}>\n        {chats.map((chat) => (\n          <div\n            key={chat.id}\n            onClick={() => navigate(`/chat/${chat.id}`)}\n            className={`p-4 border-b cursor-pointer transition hover:bg-opacity-50 ${isDark ? 'border-gray-700 bg-gray-800 hover:bg-gray-700' : 'border-gray-200 hover:bg-gray-100'}`}\n          >\n            <div className=\"flex items-center gap-3\">\n              <div className=\"w-12 h-12 rounded-full bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center text-white font-bold\">\n                {chat.name[0]}\n              </div>\n              <div className=\"flex-1\">\n                <h3 className={`font-semibold ${isDark ? 'text-white' : 'text-gray-900'}`}>{chat.name}</h3>\n                <p className={`text-sm ${isDark ? 'text-gray-400' : 'text-gray-600'}`}>{chat.lastMessage}</p>\n              </div>\n              <div className=\"text-right\">\n                <p className={`text-xs ${isDark ? 'text-gray-400' : 'text-gray-500'}`}>{chat.time}</p>\n                {chat.unread > 0 && (\n                  <span className=\"inline-block mt-1 bg-red-500 text-white text-xs font-bold rounded-full px-2 py-1\">\n                    {chat.unread}\n                  </span>\n                )}\n              </div>\n            </div>\n          </div>\n        ))}\n      </div>\n\n      {/* Bottom Navigation */}\n      <div className={`${isDark ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-t p-4 flex justify-around`}>\n        <button className=\"flex flex-col items-center gap-1 text-blue-600 hover:opacity-70\">\n          <span className=\"text-2xl\">💬</span>\n          <span className=\"text-xs\">Chat</span>\n        </button>\n        <button\n          onClick={() => navigate('/calls')}\n          className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\"\n        >\n          <span className=\"text-2xl\">📞</span>\n          <span className=\"text-xs\">Calls</span>\n        </button>\n        <button\n          onClick={() => navigate('/stories')}\n          className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\"\n        >\n          <span className=\"text-2xl\">📸</span>\n          <span className=\"text-xs\">Stories</span>\n        </button>\n        <button\n          onClick={() => navigate('/settings')}\n          className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\"\n        >\n          <span className=\"text-2xl\">⚙️</span>\n          <span className=\"text-xs\">Settings</span>\n        </button>\n      </div>\n    </div>\n  )\n}\n"
  },
  {
    "path": "client/src/pages/ChatWindow.tsx",
    "content": "import { useState } from 'react'\nimport { useParams, useNavigate } from 'react-router-dom'\n\nexport default function ChatWindow() {\n  const { id } = useParams()\n  const navigate = useNavigate()\n  const [messages, setMessages] = useState([\n    { id: 1, sender: 'Alice', text: 'Hey! How are you?', timestamp: '10:30 AM', isOwn: false },\n    { id: 2, sender: 'You', text: 'I\\'m good! How about you?', timestamp: '10:31 AM', isOwn: true },\n  ])\n  const [newMessage, setNewMessage] = useState('')\n  const [showAI, setShowAI] = useState(false)\n\n  const handleSendMessage = () => {\n    if (newMessage.trim()) {\n      setMessages([...messages, {\n        id: messages.length + 1,\n        sender: 'You',\n        text: newMessage,\n        timestamp: new Date().toLocaleTimeString(),\n        isOwn: true,\n      }])\n      setNewMessage('')\n    }\n  }\n\n  return (\n    <div className=\"h-screen flex flex-col bg-white\">\n      {/* Header */}\n      <div className=\"bg-blue-600 text-white p-4 shadow-lg flex items-center justify-between\">\n        <div className=\"flex items-center gap-3\">\n          <button onClick={() => navigate('/home')} className=\"text-xl\">←</button>\n          <div>\n            <h2 className=\"font-semibold\">Alice Johnson</h2>\n            <p className=\"text-xs opacity-75\">Active now</p>\n          </div>\n        </div>\n        <div className=\"flex gap-3\">\n          <button className=\"text-xl\">📞</button>\n          <button className=\"text-xl\">📹</button>\n          <button className=\"text-xl\">ℹ️</button>\n        </div>\n      </div>\n\n      {/* Messages */}\n      <div className=\"flex-1 overflow-y-auto p-4 space-y-4\">\n        {messages.map((msg) => (\n          <div key={msg.id} className={`flex ${msg.isOwn ? 'justify-end' : 'justify-start'}`}>\n            <div className={`max-w-xs px-4 py-2 rounded-lg ${\n              msg.isOwn\n                ? 'bg-blue-500 text-white rounded-br-none'\n                : 'bg-gray-200 text-gray-900 rounded-bl-none'\n            }`}>\n              <p>{msg.text}</p>\n              <p className={`text-xs mt-1 ${msg.isOwn ? 'text-blue-100' : 'text-gray-600'}`}>{msg.timestamp}</p>\n            </div>\n          </div>\n        ))}\n      </div>\n\n      {/* AI Assistant Panel */}\n      {showAI && (\n        <div className=\"bg-purple-50 border-t-2 border-purple-300 p-4\">\n          <div className=\"flex items-center justify-between mb-3\">\n            <h3 className=\"font-semibold text-purple-900\">🤖 AI Assistant</h3>\n            <button onClick={() => setShowAI(false)} className=\"text-xl\">✕</button>\n          </div>\n          <div className=\"space-y-2 text-sm\">\n            <p className=\"text-purple-700\"><strong>Smart Replies:</strong></p>\n            <button className=\"block w-full text-left bg-white border border-purple-300 rounded p-2 hover:bg-purple-100 text-purple-900\">\n              Thanks for letting me know!\n            </button>\n            <button className=\"block w-full text-left bg-white border border-purple-300 rounded p-2 hover:bg-purple-100 text-purple-900\">\n              That sounds great!\n            </button>\n          </div>\n        </div>\n      )}\n\n      {/* Input Area */}\n      <div className=\"bg-gray-100 p-4 border-t border-gray-300\">\n        <div className=\"flex gap-2\">\n          <input\n            type=\"text\"\n            value={newMessage}\n            onChange={(e) => setNewMessage(e.target.value)}\n            onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}\n            placeholder=\"Type a message...\"\n            className=\"flex-1 px-4 py-2 rounded-full border border-gray-300 focus:outline-none focus:ring-2 focus:ring-blue-500\"\n          />\n          <button onClick={() => setShowAI(!showAI)} className=\"text-2xl\">🤖</button>\n          <button className=\"text-2xl\">🎨</button>\n          <button onClick={handleSendMessage} className=\"text-2xl\">📤</button>\n        </div>\n      </div>\n    </div>\n  )\n}\n"
  },
  {
    "path": "client/src/pages/CallsPage.tsx",
    "content": "import { useNavigate } from 'react-router-dom'\n\nexport default function CallsPage() {\n  const navigate = useNavigate()\n  const [callHistory] = useState([\n    { id: 1, contact: 'Alice Johnson', type: 'video', duration: '45m', date: 'Today' },\n    { id: 2, contact: 'Bob Smith', type: 'voice', duration: '12m', date: 'Yesterday' },\n  ])\n  const [contacts] = useState([\n    { id: 1, name: 'Alice Johnson', status: 'online' },\n    { id: 2, name: 'Bob Smith', status: 'offline' },\n  ])\n\n  return (\n    <div className=\"h-screen flex flex-col bg-white\">\n      {/* Header */}\n      <div className=\"bg-blue-600 text-white p-4 shadow-lg flex items-center gap-3\">\n        <button onClick={() => navigate('/home')} className=\"text-xl\">←</button>\n        <h1 className=\"text-2xl font-bold\">📞 Calls</h1>\n      </div>\n\n      <div className=\"flex-1 overflow-y-auto\">\n        {/* Quick Dial */}\n        <div className=\"p-4 bg-blue-50 border-b\">\n          <h2 className=\"font-semibold text-gray-900 mb-3\">Quick Dial</h2>\n          <div className=\"grid grid-cols-3 gap-3\">\n            {contacts.map((contact) => (\n              <div key={contact.id} className=\"text-center\">\n                <div className={`w-12 h-12 rounded-full mx-auto mb-2 flex items-center justify-center font-bold text-white ${\n                  contact.status === 'online'\n                    ? 'bg-green-500'\n                    : 'bg-gray-400'\n                }`}>\n                  {contact.name[0]}\n                </div>\n                <p className=\"text-xs font-medium\">{contact.name}</p>\n                <p className=\"text-xs text-gray-500\">{contact.status}</p>\n              </div>\n            ))}\n          </div>\n        </div>\n\n        {/* Call History */}\n        <div className=\"p-4\">\n          <h2 className=\"font-semibold text-gray-900 mb-3\">Call History</h2>\n          <div className=\"space-y-2\">\n            {callHistory.map((call) => (\n              <div key={call.id} className=\"p-3 bg-gray-50 rounded-lg flex items-center justify-between\">\n                <div>\n                  <p className=\"font-semibold\">{call.contact}</p>\n                  <p className=\"text-xs text-gray-600\">{call.type === 'video' ? '📹' : '📞'} {call.duration} • {call.date}</p>\n                </div>\n                <button className=\"text-2xl\">📞</button>\n              </div>\n            ))}\n          </div>\n        </div>\n      </div>\n\n      {/* Bottom Navigation */}\n      <div className=\"bg-white border-t border-gray-200 p-4 flex justify-around\">\n        <button onClick={() => navigate('/home')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">💬</span>\n          <span className=\"text-xs\">Chat</span>\n        </button>\n        <button className=\"flex flex-col items-center gap-1 text-blue-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📞</span>\n          <span className=\"text-xs\">Calls</span>\n        </button>\n        <button onClick={() => navigate('/stories')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📸</span>\n          <span className=\"text-xs\">Stories</span>\n        </button>\n        <button onClick={() => navigate('/settings')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">⚙️</span>\n          <span className=\"text-xs\">Settings</span>\n        </button>\n      </div>\n    </div>\n  )\n}\n\nimport { useState } from 'react'\n"
  },
  {
    "path": "client/src/pages/StoriesPage.tsx",
    "content": "import { useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\n\nexport default function StoriesPage() {\n  const navigate = useNavigate()\n  const [stories] = useState([\n    { id: 1, user: 'Alice Johnson', content: 'Just finished a great workout! 💪', timeLeft: '2h 30m' },\n    { id: 2, user: 'Bob Smith', content: '🎉 Team lunch was amazing!', timeLeft: '8h 15m' },\n  ])\n  const [showUpload, setShowUpload] = useState(false)\n\n  return (\n    <div className=\"h-screen flex flex-col bg-white\">\n      {/* Header */}\n      <div className=\"bg-blue-600 text-white p-4 shadow-lg flex items-center gap-3\">\n        <button onClick={() => navigate('/home')} className=\"text-xl\">←</button>\n        <h1 className=\"text-2xl font-bold\">📸 Stories</h1>\n      </div>\n\n      <div className=\"flex-1 overflow-y-auto p-4\">\n        {/* Upload Story */}\n        <div\n          onClick={() => setShowUpload(true)}\n          className=\"mb-6 p-6 bg-gradient-to-br from-blue-400 to-purple-500 rounded-lg cursor-pointer hover:opacity-90 transition text-white text-center\"\n        >\n          <p className=\"text-4xl mb-2\">➕</p>\n          <p className=\"font-semibold\">Add Your Story</p>\n          <p className=\"text-sm opacity-75\">Share what's on your mind</p>\n        </div>\n\n        {/* Stories Feed */}\n        <div className=\"space-y-4\">\n          {stories.map((story) => (\n            <div key={story.id} className=\"p-4 bg-gradient-to-r from-blue-50 to-purple-50 rounded-lg border border-blue-200\">\n              <div className=\"flex items-center justify-between mb-3\">\n                <div className=\"flex items-center gap-3\">\n                  <div className=\"w-10 h-10 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold\">\n                    {story.user[0]}\n                  </div>\n                  <div>\n                    <p className=\"font-semibold text-gray-900\">{story.user}</p>\n                    <p className=\"text-xs text-gray-600\">{story.timeLeft} left</p>\n                  </div>\n                </div>\n                <div className=\"w-6 h-6 rounded-full border-2 border-green-500\"></div>\n              </div>\n              <p className=\"text-gray-900\">{story.content}</p>\n            </div>\n          ))}\n        </div>\n      </div>\n\n      {/* Upload Modal */}\n      {showUpload && (\n        <div className=\"fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50\">\n          <div className=\"bg-white rounded-lg p-6 w-96\">\n            <h2 className=\"text-2xl font-bold mb-4\">Upload Story</h2>\n            <div className=\"space-y-4\">\n              <textarea\n                placeholder=\"What's on your mind?\"\n                className=\"w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 h-24\"\n              />\n              <div className=\"flex gap-2\">\n                <button className=\"flex-1 bg-gray-200 text-gray-900 py-2 rounded-lg hover:bg-gray-300 transition\">\n                  📷 Photo\n                </button>\n                <button className=\"flex-1 bg-gray-200 text-gray-900 py-2 rounded-lg hover:bg-gray-300 transition\">\n                  🎥 Video\n                </button>\n              </div>\n              <div className=\"flex gap-2\">\n                <button\n                  onClick={() => setShowUpload(false)}\n                  className=\"flex-1 bg-gray-300 text-gray-900 py-2 rounded-lg hover:bg-gray-400 transition font-semibold\"\n                >\n                  Cancel\n                </button>\n                <button\n                  onClick={() => setShowUpload(false)}\n                  className=\"flex-1 bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition font-semibold\"\n                >\n                  Share Story\n                </button>\n              </div>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Bottom Navigation */}\n      <div className=\"bg-white border-t border-gray-200 p-4 flex justify-around\">\n        <button onClick={() => navigate('/home')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">💬</span>\n          <span className=\"text-xs\">Chat</span>\n        </button>\n        <button onClick={() => navigate('/calls')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📞</span>\n          <span className=\"text-xs\">Calls</span>\n        </button>\n        <button className=\"flex flex-col items-center gap-1 text-blue-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📸</span>\n          <span className=\"text-xs\">Stories</span>\n        </button>\n        <button onClick={() => navigate('/settings')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">⚙️</span>\n          <span className=\"text-xs\">Settings</span>\n        </button>\n      </div>\n    </div>\n  )\n}\n"
  },
