    "path": "client/src/pages/ProfilePage.tsx",
    "content": "import { useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\n\nexport default function ProfilePage() {\n  const navigate = useNavigate()\n  const [user] = useState({ username: 'john_doe', displayName: 'John Doe', bio: 'Hello! I use Co Chat 👋' })\n\n  return (\n    <div className=\"h-screen flex flex-col bg-white\">\n      {/* Header */}\n      <div className=\"bg-blue-600 text-white p-4 shadow-lg flex items-center gap-3\">\n        <button onClick={() => navigate('/home')} className=\"text-xl\">←</button>\n        <h1 className=\"text-2xl font-bold\">👤 Profile</h1>\n      </div>\n\n      <div className=\"flex-1 overflow-y-auto p-4\">\n        {/* Avatar Section */}\n        <div className=\"text-center mb-6\">\n          <div className=\"w-24 h-24 rounded-full bg-gradient-to-br from-blue-400 to-purple-500 mx-auto mb-4 flex items-center justify-center text-5xl\">\n            😊\n          </div>\n          <button className=\"text-blue-600 hover:underline text-sm\">Change Avatar</button>\n        </div>\n\n        {/* User Info */}\n        <div className=\"space-y-4 mb-6\">\n          <div>\n            <label className=\"block text-sm font-semibold text-gray-700 mb-2\">Display Name</label>\n            <p className=\"bg-gray-100 px-4 py-2 rounded-lg text-gray-900\">{user.displayName}</p>\n          </div>\n          <div>\n            <label className=\"block text-sm font-semibold text-gray-700 mb-2\">Username</label>\n            <p className=\"bg-gray-100 px-4 py-2 rounded-lg text-gray-900\">@{user.username}</p>\n          </div>\n          <div>\n            <label className=\"block text-sm font-semibold text-gray-700 mb-2\">Bio</label>\n            <p className=\"bg-gray-100 px-4 py-2 rounded-lg text-gray-900\">{user.bio}</p>\n          </div>\n        </div>\n\n        {/* Edit Button */}\n        <button className=\"w-full bg-blue-600 text-white font-semibold py-3 rounded-lg hover:bg-blue-700 transition mb-4\">\n          Edit Profile\n        </button>\n\n        {/* Stats */}\n        <div className=\"grid grid-cols-3 gap-4 mb-6 text-center\">\n          <div className=\"bg-blue-50 p-4 rounded-lg\">\n            <p className=\"text-2xl font-bold text-blue-600\">24</p>\n            <p className=\"text-xs text-gray-600 mt-1\">Contacts</p>\n          </div>\n          <div className=\"bg-purple-50 p-4 rounded-lg\">\n            <p className=\"text-2xl font-bold text-purple-600\">156</p>\n            <p className=\"text-xs text-gray-600 mt-1\">Messages</p>\n          </div>\n          <div className=\"bg-green-50 p-4 rounded-lg\">\n            <p className=\"text-2xl font-bold text-green-600\">8h</p>\n            <p className=\"text-xs text-gray-600 mt-1\">Talk Time</p>\n          </div>\n        </div>\n      </div>\n\n      {/* Bottom Navigation */}\n      <div className=\"bg-white border-t border-gray-200 p-4 flex justify-around\">\n        <button onClick={() => navigate('/home')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">💬</span>\n          <span className=\"text-xs\">Chat</span>\n        </button>\n        <button onClick={() => navigate('/calls')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📞</span>\n          <span className=\"text-xs\">Calls</span>\n        </button>\n        <button onClick={() => navigate('/stories')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📸</span>\n          <span className=\"text-xs\">Stories</span>\n        </button>\n        <button onClick={() => navigate('/settings')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">⚙️</span>\n          <span className=\"text-xs\">Settings</span>\n        </button>\n      </div>\n    </div>\n  )\n}\n"
  },
  {
    "path": "client/src/pages/SettingsPage.tsx",
    "content": "import { useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\n\nexport default function SettingsPage() {\n  const navigate = useNavigate()\n  const [settings, setSettings] = useState({\n    notifications: true,\n    darkMode: false,\n    language: 'English',\n    privacy: 'Friends Only',\n  })\n\n  const handleToggle = (key: string) => {\n    setSettings(prev => ({ ...prev, [key]: !prev[key] }))\n  }\n\n  return (\n    <div className=\"h-screen flex flex-col bg-white\">\n      {/* Header */}\n      <div className=\"bg-blue-600 text-white p-4 shadow-lg flex items-center gap-3\">\n        <button onClick={() => navigate('/home')} className=\"text-xl\">←</button>\n        <h1 className=\"text-2xl font-bold\">⚙️ Settings</h1>\n      </div>\n\n      <div className=\"flex-1 overflow-y-auto p-4 space-y-6\">\n        {/* Notifications */}\n        <div>\n          <h2 className=\"font-semibold text-gray-900 mb-3\">🔔 Notifications</h2>\n          <div className=\"space-y-2\">\n            <div className=\"flex items-center justify-between p-3 bg-gray-50 rounded-lg\">\n              <span className=\"text-gray-700\">Enable Notifications</span>\n              <input\n                type=\"checkbox\"\n                checked={settings.notifications}\n                onChange={() => handleToggle('notifications')}\n                className=\"w-5 h-5 rounded\"\n              />\n            </div>\n            <div className=\"flex items-center justify-between p-3 bg-gray-50 rounded-lg\">\n              <span className=\"text-gray-700\">Message Alerts</span>\n              <input type=\"checkbox\" defaultChecked className=\"w-5 h-5 rounded\" />\n            </div>\n            <div className=\"flex items-center justify-between p-3 bg-gray-50 rounded-lg\">\n              <span className=\"text-gray-700\">Call Alerts</span>\n              <input type=\"checkbox\" defaultChecked className=\"w-5 h-5 rounded\" />\n            </div>\n          </div>\n        </div>\n\n        {/* Privacy */}\n        <div>\n          <h2 className=\"font-semibold text-gray-900 mb-3\">🔐 Privacy</h2>\n          <div className=\"space-y-2\">\n            <select className=\"w-full p-3 bg-gray-50 border border-gray-300 rounded-lg text-gray-700\">\n              <option>Friends Only</option>\n              <option>Public</option>\n              <option>Private</option>\n            </select>\n            <div className=\"flex items-center justify-between p-3 bg-gray-50 rounded-lg\">\n              <span className=\"text-gray-700\">End-to-End Encryption</span>\n              <input type=\"checkbox\" defaultChecked disabled className=\"w-5 h-5 rounded\" />\n            </div>\n          </div>\n        </div>\n\n        {/* Display */}\n        <div>\n          <h2 className=\"font-semibold text-gray-900 mb-3\">🎨 Display</h2>\n          <div className=\"space-y-2\">\n            <div className=\"flex items-center justify-between p-3 bg-gray-50 rounded-lg\">\n              <span className=\"text-gray-700\">Dark Mode</span>\n              <input\n                type=\"checkbox\"\n                checked={settings.darkMode}\n                onChange={() => handleToggle('darkMode')}\n                className=\"w-5 h-5 rounded\"\n              />\n            </div>\n            <select className=\"w-full p-3 bg-gray-50 border border-gray-300 rounded-lg text-gray-700\">\n              <option>Light Theme</option>\n              <option>Dark Theme</option>\n              <option>Auto</option>\n            </select>\n          </div>\n        </div>\n\n        {/* Language */}\n        <div>\n          <h2 className=\"font-semibold text-gray-900 mb-3\">🌐 Language</h2>\n          <select className=\"w-full p-3 bg-gray-50 border border-gray-300 rounded-lg text-gray-700\">\n            <option>English</option>\n            <option>Spanish</option>\n            <option>French</option>\n            <option>German</option>\n          </select>\n        </div>\n\n        {/* Danger Zone */}\n        <div>\n          <h2 className=\"font-semibold text-gray-900 mb-3\">⚠️ Account</h2>\n          <button className=\"w-full bg-red-600 text-white py-3 rounded-lg hover:bg-red-700 transition font-semibold\">\n            Logout\n          </button>\n        </div>\n      </div>\n\n      {/* Bottom Navigation */}\n      <div className=\"bg-white border-t border-gray-200 p-4 flex justify-around\">\n        <button onClick={() => navigate('/home')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">💬</span>\n          <span className=\"text-xs\">Chat</span>\n        </button>\n        <button onClick={() => navigate('/calls')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📞</span>\n          <span className=\"text-xs\">Calls</span>\n        </button>\n        <button onClick={() => navigate('/stories')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📸</span>\n          <span className=\"text-xs\">Stories</span>\n        </button>\n        <button className=\"flex flex-col items-center gap-1 text-blue-600 hover:opacity-70\">\n          <span className=\"text-2xl\">⚙️</span>\n          <span className=\"text-xs\">Settings</span>\n        </button>\n      </div>\n    </div>\n  )\n}\n"
  },
  {
    "path": "client/src/pages/AIAssistantPage.tsx",
    "content": "import { useState } from 'react'\nimport { useNavigate } from 'react-router-dom'\n\nexport default function AIAssistantPage() {\n  const navigate = useNavigate()\n  const [activeTab, setActiveTab] = useState<'summarize' | 'translate' | 'replies'>('summarize')\n  const [summaries] = useState([\n    { chat: 'Team Dev', summary: 'Team discussed Q2 roadmap, decided on 3 major features' },\n    { chat: 'Alice', summary: 'Talked about weekend plans and upcoming birthday party' },\n  ])\n\n  return (\n    <div className=\"h-screen flex flex-col bg-white\">\n      {/* Header */}\n      <div className=\"bg-gradient-to-r from-purple-600 to-blue-600 text-white p-4 shadow-lg flex items-center gap-3\">\n        <button onClick={() => navigate('/home')} className=\"text-xl\">←</button>\n        <h1 className=\"text-2xl font-bold\">🤖 AI Assistant</h1>\n      </div>\n\n      {/* Tabs */}\n      <div className=\"flex border-b border-gray-200\">\n        <button\n          onClick={() => setActiveTab('summarize')}\n          className={`flex-1 py-3 font-semibold transition ${\n            activeTab === 'summarize'\n              ? 'text-blue-600 border-b-2 border-blue-600'\n              : 'text-gray-600 hover:text-gray-900'\n          }`}\n        >\n          📝 Summarize\n        </button>\n        <button\n          onClick={() => setActiveTab('translate')}\n          className={`flex-1 py-3 font-semibold transition ${\n            activeTab === 'translate'\n              ? 'text-blue-600 border-b-2 border-blue-600'\n              : 'text-gray-600 hover:text-gray-900'\n          }`}\n        >\n          🌐 Translate\n        </button>\n        <button\n          onClick={() => setActiveTab('replies')}\n          className={`flex-1 py-3 font-semibold transition ${\n            activeTab === 'replies'\n              ? 'text-blue-600 border-b-2 border-blue-600'\n              : 'text-gray-600 hover:text-gray-900'\n          }`}\n        >\n          💬 Smart Replies\n        </button>\n      </div>\n\n      {/* Content */}\n      <div className=\"flex-1 overflow-y-auto p-4\">\n        {activeTab === 'summarize' && (\n          <div className=\"space-y-4\">\n            <h2 className=\"text-xl font-bold text-gray-900 mb-4\">Chat Summaries</h2>\n            {summaries.map((item, idx) => (\n              <div key={idx} className=\"p-4 bg-gradient-to-br from-purple-50 to-blue-50 rounded-lg border border-purple-200\">\n                <h3 className=\"font-semibold text-gray-900 mb-2\">{item.chat}</h3>\n                <p className=\"text-gray-700\">{item.summary}</p>\n              </div>\n            ))}\n          </div>\n        )}\n\n        {activeTab === 'translate' && (\n          <div className=\"space-y-4\">\n            <h2 className=\"text-xl font-bold text-gray-900 mb-4\">Instant Translation</h2>\n            <div className=\"p-4 bg-blue-50 rounded-lg\">\n              <label className=\"block text-sm font-semibold text-gray-700 mb-2\">Select Language:</label>\n              <select className=\"w-full p-3 border border-gray-300 rounded-lg bg-white text-gray-700\">\n                <option>Spanish</option>\n                <option>French</option>\n                <option>German</option>\n                <option>Japanese</option>\n              </select>\n            </div>\n            <div className=\"p-4 bg-gray-50 rounded-lg\">\n              <p className=\"text-sm text-gray-600 mb-2\">Sample Translation:</p>\n              <p className=\"text-gray-900 italic\">\\\"Hey! How are you?\\\" → \\\"¡Hola! ¿Cómo estás?\\\"</p>\n            </div>\n          </div>\n        )}\n\n        {activeTab === 'replies' && (\n          <div className=\"space-y-4\">\n            <h2 className=\"text-xl font-bold text-gray-900 mb-4\">Smart Reply Suggestions</h2>\n            <p className=\"text-gray-600 text-sm mb-4\">AI-powered suggestions based on conversation context:</p>\n            <div className=\"space-y-2\">\n              <button className=\"w-full p-4 text-left bg-gradient-to-r from-blue-50 to-blue-100 border border-blue-300 rounded-lg hover:bg-blue-100 transition\">\n                <p className=\"font-semibold text-blue-900\">Thanks for letting me know!</p>\n                <p className=\"text-xs text-blue-700 mt-1\">Perfect for acknowledgments</p>\n              </button>\n              <button className=\"w-full p-4 text-left bg-gradient-to-r from-green-50 to-green-100 border border-green-300 rounded-lg hover:bg-green-100 transition\">\n                <p className=\"font-semibold text-green-900\">That sounds great!</p>\n                <p className=\"text-xs text-green-700 mt-1\">Great for positive feedback</p>\n              </button>\n              <button className=\"w-full p-4 text-left bg-gradient-to-r from-purple-50 to-purple-100 border border-purple-300 rounded-lg hover:bg-purple-100 transition\">\n                <p className=\"font-semibold text-purple-900\">Can we chat about this later?</p>\n                <p className=\"text-xs text-purple-700 mt-1\">Perfect for deferring conversations</p>\n              </button>\n            </div>\n          </div>\n        )}\n      </div>\n\n      {/* Bottom Navigation */}\n      <div className=\"bg-white border-t border-gray-200 p-4 flex justify-around\">\n        <button onClick={() => navigate('/home')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">💬</span>\n          <span className=\"text-xs\">Chat</span>\n        </button>\n        <button onClick={() => navigate('/calls')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📞</span>\n          <span className=\"text-xs\">Calls</span>\n        </button>\n        <button onClick={() => navigate('/stories')} className=\"flex flex-col items-center gap-1 text-gray-600 hover:opacity-70\">\n          <span className=\"text-2xl\">📸</span>\n          <span className=\"text-xs\">Stories</span>\n        </button>\n        <button className=\"flex flex-col items-center gap-1 text-purple-600 hover:opacity-70\">\n          <span className=\"text-2xl\">🤖</span>\n          <span className=\"text-xs\">AI</span>\n        </button>\n      </div>\n    </div>\n  )\n}\n"
  },
  {
    "path": "client/vite.config.ts",
    "content": "import { defineConfig } from 'vite'\nimport react from '@vitejs/plugin-react'\n\nexport default defineConfig({\n  plugins: [react()],\n  server: {\n    port: 3000,\n    proxy: {\n      '/api': {\n        target: 'http://localhost:3001',\n        changeOrigin: true,\n      },\n    },\n  },\n})\n"
  },
  {
    "path": \"client/tsconfig.json\",\n    \"content\": \"{\\n  \\\"compilerOptions\\\": {\\n    \\\"target\\\": \\\"ES2020\\\",\\n    \\\"useDefineForClassFields\\\": true,\\n    \\\"lib\\\": [\\\"ES2020\\\", \\\"DOM\\\", \\\"DOM.Iterable\\\"],\\n    \\\"module\\\": \\\"ESNext\\\",\\n    \\\"skipLibCheck\\\": true,\\n\\n    /* Bundler mode */\\n    \\\"moduleResolution\\\": \\\"bundler\\\",\\n    \\\"allowImportingTsExtensions\\\": true,\\n    \\\"resolveJsonModule\\\": true,\\n    \\\"isolatedModules\\\": true,\\n    \\\"noEmit\\\": true,\\n    \\\"jsx\\\": \\\"react-jsx\\\",\\n\\n    /* Linting */\\n    \\\"strict\\\": true,\\n    \\\"noUnusedLocals\\\": true,\\n    \\\"noUnusedParameters\\\": true,\\n    \\\"noFallthroughCasesInSwitch\\\": true\\n  },\\n  \\\"include\\\": [\\\"src\\\"],\\n  \\\"references\\\": [{ \\\"path\\\": \\\"./tsconfig.node.json\\\" }]\\n}\"\n  },\n  {\n    \"path\": \"server/package.json\",\n    \"content\": \"{\\n  \\\"name\\\": \\\"co-chat-server\\\",\\n  \\\"version\\\": \\\"1.0.0\\\",\\n  \\\"type\\\": \\\"module\\\",\\n  \\\"scripts\\\": {\\n    \\\"dev\\\": \\\"nodemon src/index.ts\\\",\\n    \\\"build\\\": \\\"tsc\\\",\\n    \\\"start\\\": \\\"node dist/index.js\\\",\\n    \\\"test\\\": \\\"jest\\\"\\n  },\\n  \\\"dependencies\\\": {\\n    \\\"express\\\": \\\"^4.18.2\\\",\\n    \\\"socket.io\\\": \\\"^4.6.1\\\",\\n    \\\"jsonwebtoken\\\": \\\"^9.1.0\\\",\\n    \\\"bcrypt\\\": \\\"^5.1.1\\\",\\n    \\\"mongoose\\\": \\\"^7.5.0\\\",\\n    \\\"cors\\\": \\\"^2.8.5\\\",\\n    \\\"dotenv\\\": \\\"^16.3.1\\\",\\n    \\\"libsodium.js\\\": \\\"^0.7.10\\\",\\n    \\\"uuid\\\": \\\"^9.0.0\\\"\\n  },\\n  \\\"devDependencies\\\": {\\n    \\\"@types/express\\\": \\\"^4.17.20\\\",\\n    \\\"@types/node\\\": \\\"^20.8.0\\\",\\n    \\\"typescript\\\": \\\"^5.2.2\\\",\\n    \\\"nodemon\\\": \\\"^3.0.1\\\",\\n    \\\"ts-node\\\": \\\"^10.9.1\\\",\\n    \\\"jest\\\": \\\"^29.7.0\\\",\\n    \\\"@types/jest\\\": \\\"^29.5.5\\\"\\n  }\\n}\"\n  },\n  {\n    \"path\": \"server/src/index.ts\",\n    \"content\": \"import express from 'express'\\nimport http from 'http'\\nimport { Server as SocketIOServer } from 'socket.io'\\nimport cors from 'cors'\\nimport dotenv from 'dotenv'\\n\\ndotenv.config()\\n\\nconst app = express()\\nconst server = http.createServer(app)\\nconst io = new SocketIOServer(server, {\\n  cors: {\\n    origin: process.env.CLIENT_URL || 'http://localhost:3000',\\n    methods: ['GET', 'POST'],\\n  },\\n})\\n\\nconst PORT = process.env.PORT || 3001\\n\\n// Middleware\\napp.use(cors())\\napp.use(express.json())\\n\\n// Basic health check\\napp.get('/api/health', (req, res) => {\\n  res.json({ status: 'Server is running' })\\n})\\n\\n// WebSocket connection\\nio.on('connection', (socket) => {\\n  console.log(`User connected: ${socket.id}`)\\n\\n  socket.on('send_message', (data) => {\\n    io.emit('receive_message', data)\\n    console.log('Message received:', data)\\n  })\\n\\n  socket.on('disconnect', () => {\\n    console.log(`User disconnected: ${socket.id}`)\\n  })\\n})\\n\\nserver.listen(PORT, () => {\\n  console.log(`✨ Co Chat Server running on port ${PORT}`)\\n})\"\n  }\n]\n"}

