{"content": "import express from 'express'
import http from 'http'
import { Server as SocketIOServer } from 'socket.io'
import cors from 'cors'
import dotenv from 'dotenv'

dotenv.config()

const app = express()
const server = http.createServer(app)
const io = new SocketIOServer(server, {
  cors: {
    origin: process.env.CLIENT_URL || 'http://localhost:3000',
    methods: ['GET', 'POST'],
  },
})

const PORT = process.env.PORT || 3001

// Middleware
app.use(cors())
app.use(express.json())

// Basic health check
app.get('/api/health', (req, res) => {
  res.json({ status: 'Server is running' })
})

// Authentication routes (placeholder)
app.post('/api/auth/register', (req, res) => {
  // TODO: Implement registration
  res.json({ message: 'Registration endpoint' })
})

app.post('/api/auth/login', (req, res) => {
  // TODO: Implement login
  res.json({ message: 'Login endpoint' })
})

// Messages routes (placeholder)
app.get('/api/messages/:chatId', (req, res) => {
  // TODO: Fetch messages for chat
  res.json({ messages: [] })
})

// WebSocket connection
io.on('connection', (socket) => {
  console.log(`User connected: ${socket.id}`)

  socket.on('join_chat', (data) => {
    socket.join(data.chatId)
    console.log(`User ${socket.id} joined chat ${data.chatId}`)
  })

  socket.on('send_message', (data) => {
    io.to(data.chatId).emit('receive_message', data)
    console.log('Message received:', data)
  })

  socket.on('typing', (data) => {
    socket.to(data.chatId).emit('user_typing', { userId: socket.id })
  })

  socket.on('disconnect', () => {
    console.log(`User disconnected: ${socket.id}`)
  })
})

server.listen(PORT, () => {
  console.log(`✨ Co Chat Server running on port ${PORT}`)
})
